for f in AlgebraicJacobian/Cohomology/BasicOpenCech.lean AlgebraicJacobian/Cohomology/StructureSheafModuleK.lean AlgebraicJacobian/Differentials.lean AlgebraicJacobian/Genus.lean AlgebraicJacobian/Jacobian.lean AlgebraicJacobian/Picard/Functor.lean AlgebraicJacobian/Rigidity.lean AlgebraicJacobian/AbelJacobi.lean AlgebraicJacobian/Picard/LineBundle.lean AlgebraicJacobian/Cohomology/SheafCompose.lean AlgebraicJacobian/Cohomology/StructureSheafAb.lean AlgebraicJacobian/Picard/FunctorAb.lean AlgebraicJacobian/Cohomology/MayerVietorisCore.lean AlgebraicJacobian/Cohomology/MayerVietorisCover.lean; do
  if [ -f "$f" ]; then
    # find sorries that are not inside line comments
    n=$(awk '
      BEGIN { in_block = 0; count = 0 }
      {
        line = $0
        # strip block comments inline (rough)
        while (match(line, /\/-/) && match(line, /-\//)) {
          a = index(line, "/-")
          b = index(line, "-/")
          if (b > a) { line = substr(line, 1, a-1) substr(line, b+2) } else break
        }
        # handle multi-line block comments
        if (in_block) {
          if (match(line, /-\//)) { in_block = 0; line = substr(line, RSTART+2) } else next
        }
        if (match(line, /\/-/)) { in_block = 1; line = substr(line, 1, RSTART-1) }
        # strip line comments
        if (match(line, /--/)) { line = substr(line, 1, RSTART-1) }
        # count sorry tokens
        while (match(line, /\<sorry\>/)) { count++; line = substr(line, RSTART+RLENGTH) }
      }
      END { print count }
    ' "$f")
    echo "$n  $f"
  fi
done

